    final dateStamp = _formatDateStamp(now);

    final canonicalUri = uri.path.isEmpty ? '/' : uri.path;
    final canonicalQueryString = _canonicalQuery(uri.queryParametersAll);

    final host = uri.host;

    final allHeaders = <String, String>{};
    allHeaders.addAll(headers.map((k, v) => MapEntry(k.toLowerCase(), v.trim())));
    allHeaders['host'] = host;
    allHeaders['x-amz-date'] = amzDate;
    allHeaders['x-amz-content-sha256'] = payloadHashHex;
    if (sessionToken != null && sessionToken!.isNotEmpty) {
      allHeaders['x-amz-security-token'] = sessionToken!;
    }

    final sortedHeaderKeys = allHeaders.keys.toList()..sort();
    final canonicalHeaders = StringBuffer();
    for (final k in sortedHeaderKeys) {
      canonicalHeaders.write('$k:${allHeaders[k]}\n');
    }
    final signedHeaders = sortedHeaderKeys.join(';');

    final canonicalRequest = [
      method.toUpperCase(),
      canonicalUri,
      canonicalQueryString,
      canonicalHeaders.toString(),
      signedHeaders,
      payloadHashHex,
    ].join('\n');

    final algorithm = 'AWS4-HMAC-SHA256';
    final credentialScope = '$dateStamp/$region/$service/aws4_request';
    final stringToSign = [
      algorithm,
      amzDate,
      credentialScope,
      sha256.convert(utf8.encode(canonicalRequest)).toString(),
    ].join('\n');

    final signingKey = _getSignatureKey(secretAccessKey, dateStamp, region, service);
    final signature = _hmacHex(signingKey, utf8.encode(stringToSign));

    final authorizationHeader =
        '$algorithm Credential=$accessKeyId/$credentialScope, SignedHeaders=$signedHeaders, Signature=$signature';

    final outHeaders = <String, String>{};
    outHeaders.addAll(allHeaders);
    outHeaders['authorization'] = authorizationHeader;

    return AwsSignedRequest(uri: uri, headers: outHeaders);
  }

  String _canonicalQuery(Map<String, List<String>> qpAll) {
    if (qpAll.isEmpty) return '';
    final items = <MapEntry<String, String>>[];
    for (final e in qpAll.entries) {
      final k = _awsEncode(e.key);
      final values = e.value.isEmpty ? [''] : e.value;
      for (final v in values) {
        items.add(MapEntry(k, _awsEncode(v)));
      }
    }
    items.sort((a, b) {
      final c = a.key.compareTo(b.key);
      if (c != 0) return c;
      return a.value.compareTo(b.value);
    });
    return items.map((e) => '${e.key}=${e.value}').join('&');
  }

  String _awsEncode(String s) {
    return Uri.encodeQueryComponent(s)
        .replaceAll('+', '%20')
        .replaceAll('*', '%2A')
        .replaceAll('%7E', '~');
  }

  List<int> _getSignatureKey(String key, String dateStamp, String regionName, String serviceName) {
    final kDate = _hmac(utf8.encode('AWS4$key'), utf8.encode(dateStamp));
    final kRegion = _hmac(kDate, utf8.encode(regionName));
    final kService = _hmac(kRegion, utf8.encode(serviceName));
